import unittest
from two_fer import two_fer

class TwoFerTest(unittest.TestCase):
    def test_no_name(self):
        self.assertEqual(two_fer(), 'One for you, one for me.')
    def test_a_name(self):
        self.assertEqual(two_fer('Alice'), 'One for Alice, one for me.')
    def test_another_name(self):
        self.assertEqual(two_fer('Bob'), 'One for Bob, one for me.')

if __name__ == '__main__':
    unittest.main()

import unittest
from bob import response

class BobTest(unittest.TestCase):
    def test_stating_something(self):
        self.assertEqual(response('Tom-ay-to, tom-ato.'), 'Whatever.')
    def test_shouting(self):
        self.assertEqual(response('WATCH OUT!'), 'Whoa, chill out!')
    def test_asking_a_question(self):
        self.assertEqual(response('Does this cryogenic chamber make me look fat?'), 'Sure.')
    def test_silence(self):
        self.assertEqual(response(''), 'Fine. Be that way!')
    def test_yelling_a_question(self):
        self.assertEqual(response('WHAT THE HELL WERE YOU THINKING?'), 'Calm down, I know what I\'m doing!')

if __name__ == '__main__':
    unittest.main()

import unittest
from hamming import distance

class HammingTest(unittest.TestCase):
    def test_empty_strands(self):
        self.assertEqual(distance('', ''), 0)
    def test_single_letter_identical(self):
        self.assertEqual(distance('A', 'A'), 0)
    def test_single_letter_different(self):
        self.assertEqual(distance('G', 'T'), 1)
    def test_long_strands(self):
        self.assertEqual(distance('GGACGGATTCTG', 'AGGACGGATTCT'), 9)
    def test_disallow_when_unequal_length(self):
        with self.assertRaises(ValueError):
            distance('AATG', 'AAA')

if __name__ == '__main__':
    unittest.main()
